class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Photo Analyzer',
      home: PhotoUploadScreen(),
    );
  }
}

class PhotoUploadScreen extends StatefulWidget {
  @override
  _PhotoUploadScreenState createState() => _PhotoUploadScreenState();
}

class _PhotoUploadScreenState extends State<PhotoUploadScreen> {
  File? _image;
  String _analysisResult = '';
  bool _isLoading = false;

  Future<void> _pickImage() async {
    final picker = ImagePicker();
    final pickedFile = await picker.pickImage(source: ImageSource.gallery);
    
    if (pickedFile != null) {
      setState(() {
        _image = File(pickedFile.path);
        _analysisResult = '';
      });
    }
  }

  Future<void> _uploadAndAnalyze() async {
    if (_image == null) return;
    
    setState(() => _isLoading = true);
    
    try {
      final s3Url = await _uploadToS3(_image!);
      final analysis = await _analyzeWithVision(_image!);
      
      setState(() {
        _analysisResult = 'Uploaded to: $s3Url\n\nAnalysis:\n$analysis';
        _isLoading = false;
      });
    } catch (e) {
      setState(() {
        _analysisResult = 'Error: $e';
        _isLoading = false;
      });
    }
  }

  Future<String> _uploadToS3(File file) async {
    // Use environment variables
    final accessKey = dotenv.env['AWS_ACCESS_KEY']!;
    final secretKey = dotenv.env['AWS_SECRET_KEY']!;
    final bucket = dotenv.env['AWS_BUCKET']!;
    final region = dotenv.env['AWS_REGION']!;
    
    // Implementation using AWS SDK or presigned URLs
    return 'https://$bucket.s3.$region.amazonaws.com/${file.path.split('/').last}';
  }

  Future<String> _analyzeWithVision(File file) async {
    final apiKey = dotenv.env['GOOGLE_VISION_KEY']!;
    final bytes = await file.readAsBytes();
    final base64Image = base64Encode(bytes);
    
    final response = await http.post(
      Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$apiKey'),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({
        'requests': [
          {
            'image': {'content': base64Image},
            'features': [
              {'type': 'LABEL_DETECTION', 'maxResults': 5}
            ]
          }
        ]
      }),
    );
    
    final data = jsonDecode(response.body);
    return jsonEncode(data);
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Photo Analyzer')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            if (_image != null) Image.file(_image!, height: 200),
            ElevatedButton(
              onPressed: _pickImage,
              child: Text('Pick Image'),
            ),
            ElevatedButton(
              onPressed: _isLoading ? null : _uploadAndAnalyze,
              child: Text(_isLoading ? 'Processing...' : 'Upload & Analyze'),
            ),
            Padding(
              padding: EdgeInsets.all(16),
              child: Text(_analysisResult),
            ),
          ],
        ),
      ),
    );
  }
}